import { useState } from "react";
import EspacioContacto from "./componentes/espacio-contacto/espacio-contacto";
import IniciarS from "./componentes/iniciar-s/iniciar-s";
import Registrarse from "./componentes/registrarse/registrarse";
import "./contacto.css"

function Contacto() {
    const [iniciar, useIniciar] = true;

    const [opacityiniciar, useOpacityiniciar] = useState(0);
    const [filteriniciar, usefilteriniciar] = useState(0);

    const [opacityregistrarse, useOpacityregistrarse] = useState(0);
    const [filterregistrarse, usefilterregistrarse] = useState(0);


    if (iniciar = true) {
        useOpacityiniciar(1);
        usefilteriniciar(0);

        useOpacityregistrarse(0);
        usefilterregistrarse(4);
    } else {
        useOpacityregistrarse(1);
        usefilterregistrarse(0);

        useOpacityiniciar(0);
        usefilteriniciar(4);
    }

    return (
        <div className="contacto-container">
            <EspacioContacto />
            <IniciarS opacity={opacityiniciar} filter={filteriniciar} />
            <Registrarse opacity={opacityregistrarse} filter={filterregistrarse} />
        </div>
    )
}

export default Contacto;
